args.query:
SELECT Id, OpportunityId, AccountId, ContactId, Name, Description, Status, CreatedDate, ExpirationDate
FROM Quote
WHERE REPLACE(Id,'#','') = REPLACE('0Q0Wt000001WSDVKA4','#','');

