args.query:
SELECT pbe.Id as PricebookEntryId, pbe.UnitPrice as ListUnitPrice, pbe.Product2Id, p2.Name as ProductName
FROM PricebookEntry pbe
JOIN Product2 p2 ON REPLACE(p2.Id,'#','')=REPLACE(pbe.Product2Id,'#','');

